export declare const BG_VS_SOURCE = "#version 300 es\nlayout(location = 0) in vec3 a_position;\nlayout(location = 1) in float a_size;\nlayout(location = 2) in float a_brightness;\n\nuniform mat4 u_projection;\nuniform mat4 u_view;\n\nout float v_brightness;\n\nvoid main() {\n    gl_Position = u_projection * u_view * vec4(a_position, 1.0);\n    gl_PointSize = a_size;\n    v_brightness = a_brightness;\n}\n";
export declare const BG_FS_SOURCE = "#version 300 es\nprecision mediump float;\n\nin float v_brightness;\nout vec4 outColor;\n\nvoid main() {\n    // Soft round point with Gaussian falloff\n    float d = length(gl_PointCoord - vec2(0.5));\n    float alpha = smoothstep(0.5, 0.2, d);\n    if(alpha <= 0.0) discard;\n    \n    outColor = vec4(0.8, 0.9, 1.0, v_brightness * 0.4 * alpha);\n}\n";
